const express = require('express');
const http = require('http');
const app = express();

// Middleware to parse JSON bodies
app.use(express.json());

// Load plugins from environment variables or configuration files
function loadPlugins() {
  const plugins = [];
  const pluginSources = process.env.PLUGIN_SOURCES ? process.env.PLUGIN_SOURCES.split(',') : [];

  pluginSources.forEach(source => {
    try {
      const pluginCode = require(source);
      if (typeof pluginCode === 'function') {
        plugins.push(pluginCode);
      }
    } catch (err) {
      console.error(`Failed to load plugin from ${source}:`, err);
    }
  });

  return plugins;
}

// Apply plugins to modify requests and responses
function applyPlugins(plugins, req, res, next) {
  let index = 0;

  function nextPlugin(err) {
    if (err) {
      return next(err);
    }

    if (index >= plugins.length) {
      return next();
    }

    const plugin = plugins[index++];
    try {
      plugin(req, res, nextPlugin);
    } catch (err) {
      next(err);
    }
  }

  nextPlugin();
}

// Load plugins
const plugins = loadPlugins();

// Use plugins in the request handling pipeline
app.use((req, res, next) => applyPlugins(plugins, req, res, next));

// Example route
app.get('/', (req, res) => {
  res.send('Hello from API Gateway');
});

// Start the server
const server = http.createServer(app);
const PORT = process.env.PORT || 3000;
server.listen(PORT, () => {
  console.log(`API Gateway running on port ${PORT}`);
});